//component for the to-do list
class TodoList extends Component {
  constructor(props) {
    super(props);
    //initializing state variables
    this.state = {
      todos: [],
      input: ''
    }
    //binding state variables
    this.handleChange = this.handleChange.bind(this);
    this.addTodo = this.addTodo.bind(this);
    this.deleteTodo = this.deleteTodo.bind(this);
    this.editTodo = this.editTodo.bind(this);
  }

  //function for handling change in input 
  handleChange(e) {
    this.setState({
      input: e.target.value
    });
  }

  //function to add todo
  addTodo(todo) {
    if (todo.length > 0) {
      this.setState({
        todos: [...this.state.todos, todo],
        input: ''
      })
    }
  }

  //function to delete todo 
  deleteTodo(index) {
    let todos = this.state.todos;
    todos.splice(index, 1);
    this.setState({
      todos
    });
  }

  //function to edit todo  
  editTodo(index, newTodo ) {
    let todos = this.state.todos;
    todos[index] = newTodo;
    this.setState({
      todos
    });
  }

  //function for rendering the component 
  render() {
    //setting up todo inputs
    let todoInput;
    todoInput = (
      <div>
        <input value={this.state.input} onChange={this.handleChange} type="text"/>
        <button onClick={() => this.addTodo(this.state.input)}>+</button>
      </div>
    );

    //setting up todos list 
    let todos = this.state.todos.map((todo, index) => {
      return (
        <div key={index} >
          <Todo editTodoFn={this.editTodo} deleteTodoFn={this.deleteTodo} id={index} todo={todo}/>
        </div> 
      )
    });

    //rendering the list
    return (
      <div>
        {todoInput}
        {todos}
      </div>
    );
  }
}

//export the todolist
export default TodoList;

