function pigLatinTranslator(str) {
 // Split the string into an array
 const strArr = str.split(' ');
 // The final output
 const translated = [];
 const vowels = ['a', 'e', 'i', 'o', 'u'];

 // Loop over the array
 for (let word of strArr) {
 // Check if the word starts with a vowel
 if (vowels.indexOf(word[0].toLowerCase()) !== -1) {
 // If so, add 'way' to the end
 translated.push(word + 'way');
 } else {
 // Otherwise, collect the consonants
 let consonantCluster = '';
 // Loop until you find a vowel- or until you reach the maximum length you can reach
 for (let i = 0; i < word.length; i++) {
 if (vowels.indexOf(word[i].toLowerCase()) === -1) {
 consonantCluster += word[i];
 } else {
 break;
 }
 }
 // Add the consonants + 'ay' to the end
 translated.push(word.substr(consonantCluster.length) + consonantCluster + 'ay');
 }
 }
 // Join the array and return it
 return translated.join(' ');
}

