const board = [["-", "-", "-"], ["-", "-", "-"], ["-", "-", "-"]];
let turn = false; // false for player, true for AI
let aiSymbol = "O";
let playerSymbol = "X";

function getAIMove() {
 // Get available moves
 let availableMoves = board.flat().filter(pos => pos === "-");
 // Select random move
 let moveIndex = Math.floor(Math.random() * availableMoves.length);
 let move = availableMoves[moveIndex];
 // Return move
 return move;
}

function updateBoard(move, symbol) {
 // Find row and col of move
 let rowCount = 0;
 let colCount = 0;
 for (let row of board) {
 for (let col of row) {
 if (col === move) {
 rowCount = board.indexOf(row);
 colCount = row.indexOf(col);
 break;
 }
 }
 }
 // Update board
 board[rowCount][colCount] = symbol;
}

function makeMove() {
 // AI move
 let move = getAIMove();
 updateBoard(move, aiSymbol);
 turn = false;
 // Player move
 if (!checkWinner()) {
 move = prompt("Enter your move (0-8):");
 updateBoard(move, playerSymbol);
 turn = true;
 }
 checkWinner();
}

function checkWinner() {
 // Check rows and columns
 for (let i = 0; i < 3; i++) {
 // rows
 if (board[i][0] === board[i][1] && board[i][1] === board[i][2]
 && board[i][2] !== "-") {
 return true;
 }
 // columns
 if (board[0][i] === board[1][i] && board[1][i] === board[2][i]
 && board[2][i] !== "-") {
 return true;
 }
 }
 // Check diagonals
 if (board[0][0] === board[1][1] && board[1][1] === board[2][2]
 && board[2][2] !== "-") {
 return true;
 }
 if (board[0][2] === board[1][1] && board[1][1] === board[2][0]
 && board[2][0] !== "-") {
 return true;
 }
 return false;
};

