class WordIterator {
 constructor(str) {
 this.str = str;
 this.index = 0;
 }

 next() {
 const word = '';
 while (this.index < this.str.length && this.str[this.index] !== ' ') {
 word += this.str[this.index];
 this.index++;
 }

 while (this.index < this.str.length && this.str[this.index] === ' ') {
 this.index++;
 }

 if (word) {
 return { value: word, done: false};
 } else {
 return { done: true };
 }
 }
}

