function fibonacciSum(n) {
 let curr = 1;
 let prev = 0;
 let sum  = 0;

 while (curr <= n) {
  if (curr % 2 == 0) {
   sum += curr;
  }

  let temp = curr;
  curr += prev;
  prev = temp;
 }
 return sum;
}

